package com.exam.controller;

import com.baomidou.mybatisplus.core.metadata.IPage;
import com.exam.dto.*;
import com.exam.service.ExamRecordService;
import jakarta.validation.Valid;
import lombok.extern.slf4j.Slf4j;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.bind.annotation.*;

/**
 * 考生端接口
 */
@Slf4j
@RestController
@RequestMapping("/api")
public class ExamController {

    private final ExamRecordService examRecordService;

    public ExamController(ExamRecordService examRecordService) {
        this.examRecordService = examRecordService;
    }

    /**
     * 查询可参加的考试列表
     */
    @GetMapping("/exams")
    public Result<IPage<ExamDetailResponse>> listExams(
            @RequestParam(defaultValue = "1") int page,
            @RequestParam(defaultValue = "10") int size) {
        Long userId = getCurrentUserId();
        return Result.ok(examRecordService.listExams(userId, page, size));
    }

    /**
     * 查询考试详情
     */
    @GetMapping("/exams/{id}")
    public Result<ExamDetailResponse> getExamDetail(@PathVariable Long id) {
        Long userId = getCurrentUserId();
        return Result.ok(examRecordService.getExamDetail(id, userId));
    }

    /**
     * 开始考试
     */
    @PostMapping("/exams/{id}/start")
    public Result<ExamStartResponse> startExam(@PathVariable Long id) {
        Long userId = getCurrentUserId();
        log.info("[lbl][Exam][START] 开始考试请求, examId={}, userId={}", id, userId);
        return Result.ok(examRecordService.startExam(id, userId));
    }

    /**
     * 提交考试
     */
    @PostMapping("/exams/{id}/submit")
    public Result<ExamSubmitResponse> submitExam(@PathVariable Long id,
                                                  @Valid @RequestBody ExamSubmitRequest req) {
        Long userId = getCurrentUserId();
        log.info("[lbl][Exam][SUBMIT] 提交考试请求, examId={}, recordId={}, userId={}, answerCount={}",
                id, req.getRecordId(), userId, req.getAnswers() != null ? req.getAnswers().size() : 0);
        return Result.ok(examRecordService.submitExam(req, userId));
    }

    /**
     * 查询考试记录列表
     */
    @GetMapping("/records")
    public Result<IPage<RecordDetailResponse>> listRecords(
            @RequestParam(defaultValue = "1") int page,
            @RequestParam(defaultValue = "10") int size) {
        Long userId = getCurrentUserId();
        return Result.ok(examRecordService.listRecords(userId, page, size));
    }

    /**
     * 查询考试记录详情
     */
    @GetMapping("/records/{id}")
    public Result<RecordDetailResponse> getRecordDetail(@PathVariable Long id) {
        Long userId = getCurrentUserId();
        return Result.ok(examRecordService.getRecordDetail(id, userId));
    }

    /**
     * 从 SecurityContext 获取当前用户 ID
     */
    private Long getCurrentUserId() {
        return Long.parseLong(SecurityContextHolder.getContext().getAuthentication().getName());
    }
}

