            throw new BizException(ErrorCode.FORBIDDEN);
        }

        Exam exam = examMapper.selectById(record.getExamId());
        String examTitle = exam != null ? exam.getTitle() : "";

        // 查询答题明细
        List<AnswerDetail> answerDetails = answerDetailMapper.selectList(
                new LambdaQueryWrapper<AnswerDetail>()
                        .eq(AnswerDetail::getRecordId, recordId));

        // 查询对应题目
        List<Long> questionIds = answerDetails.stream()
                .map(AnswerDetail::getQuestionId)
                .collect(Collectors.toList());
        Map<Long, QuestionBank> questionMap = questionIds.isEmpty()
                ? Collections.emptyMap()
                : questionBankMapper.selectBatchIds(questionIds).stream()
                        .collect(Collectors.toMap(QuestionBank::getId, Function.identity()));

        // 构建答题明细 VO
        boolean showAnswer = exam != null && Boolean.TRUE.equals(exam.getShowAnswer());
        boolean showAnalysis = exam != null && Boolean.TRUE.equals(exam.getShowAnalysis());

        List<RecordDetailResponse.AnswerDetailVO> answerVOs = answerDetails.stream()
                .map(ad -> {
                    QuestionBank q = questionMap.get(ad.getQuestionId());
                    RecordDetailResponse.AnswerDetailVO vo = new RecordDetailResponse.AnswerDetailVO();
                    vo.setQuestionId(ad.getQuestionId());
                    vo.setUserAnswer(ad.getUserAnswer());
                    vo.setIsCorrect(ad.getIsCorrect());
                    if (q != null) {
                        vo.setContent(q.getContent());
                        vo.setOptionA(q.getOptionA());
                        vo.setOptionB(q.getOptionB());
                        vo.setOptionC(q.getOptionC());
                        vo.setOptionD(q.getOptionD());
                        vo.setCorrectAnswer(showAnswer ? q.getCorrectAnswer() : null);
                        vo.setAnalysis(showAnalysis ? q.getAnalysis() : null);
                    }
                    return vo;
                })
                .collect(Collectors.toList());

        RecordDetailResponse response = buildRecordSummary(record, examTitle);
        response.setAnswers(answerVOs);
        return response;
    }

    // ==================== 私有方法 ====================

    /**
     * 查询已发布考试，不存在或未发布则抛异常
     */
    private Exam getPublishedExamOrThrow(Long examId) {
        Exam exam = examMapper.selectById(examId);
        if (exam == null || exam.getStatus() != ExamStatus.PUBLISHED) {
            throw new BizException(ErrorCode.EXAM_NOT_PUBLISHED);
        }
        return exam;
    }

    /**
     * 检查用户是否有权访问该考试
     */
    private void checkAccess(Exam exam, Long userId) {
        if (!hasAccess(exam, userId)) {
            throw new BizException(ErrorCode.FORBIDDEN);
        }
    }

    /**
     * 判断用户是否有权访问该考试
     */
    private boolean hasAccess(Exam exam, Long userId) {
        if (exam.getAccessMode() == AccessMode.OPEN) {
            return true;
        }
        // 白名单模式：检查用户是否在白名单中
        long count = examWhitelistMapper.selectCount(
                new LambdaQueryWrapper<ExamWhitelist>()
                        .eq(ExamWhitelist::getExamId, exam.getId())
                        .eq(ExamWhitelist::getUserId, userId));
        return count > 0;
    }

    /**
     * 统计用户在某考试下已完成的记录数（submitted + timeout）
     */
    private long countCompletedRecords(Long examId, Long userId) {
        return examRecordMapper.selectCount(
                new LambdaQueryWrapper<ExamRecord>()
                        .eq(ExamRecord::getExamId, examId)
                        .eq(ExamRecord::getUserId, userId)
                        .in(ExamRecord::getStatus, RecordStatus.SUBMITTED, RecordStatus.TIMEOUT));
    }

    /**
     * 抽题逻辑：随机抽取指定数量的题目
     */
    private List<QuestionBank> drawQuestions(List<QuestionBank> allQuestions, Integer questionCount) {
        List<QuestionBank> pool = new ArrayList<>(allQuestions);
        if (questionCount == null || questionCount == 0 || questionCount >= pool.size()) {
            // 使用全部题目，打乱顺序
            Collections.shuffle(pool);
            return pool;
        }
        // 随机抽取指定数量
        Collections.shuffle(pool);
        List<QuestionBank> selected = new ArrayList<>(pool.subList(0, questionCount));
        // 再次打乱保证随机顺序
        Collections.shuffle(selected);
        return selected;
    }

    /**
     * 构建考试详情响应
     */
    private ExamDetailResponse buildExamDetailResponse(Exam exam, Long userId) {
        ExamDetailResponse resp = new ExamDetailResponse();
        resp.setId(exam.getId());
        resp.setTitle(exam.getTitle());
        resp.setStatus(exam.getStatus().getValue());
        resp.setTimeLimitMin(exam.getTimeLimitMin());
        resp.setQuestionCount(exam.getQuestionCount());
        resp.setMaxAttempts(exam.getMaxAttempts());
        resp.setShowAnswer(exam.getShowAnswer());
        resp.setShowAnalysis(exam.getShowAnalysis());
        resp.setAccessMode(exam.getAccessMode().getValue());

        // 计算剩余次数
        if (exam.getMaxAttempts() == null || exam.getMaxAttempts() == 0) {
            resp.setRemainingAttempts(null);
        } else {
            long completed = countCompletedRecords(exam.getId(), userId);
            resp.setRemainingAttempts(Math.max(0, exam.getMaxAttempts() - (int) completed));
        }
        return resp;
    }

    /**
     * 构建记录摘要（不含答题明细）
     */
    private RecordDetailResponse buildRecordSummary(ExamRecord record, String examTitle) {
        RecordDetailResponse resp = new RecordDetailResponse();
        resp.setId(record.getId());
        resp.setExamId(record.getExamId());
        resp.setExamTitle(examTitle);
        resp.setScore(record.getScore());
        resp.setStartTime(record.getStartTime());
        resp.setEndTime(record.getEndTime());
        resp.setStatus(record.getStatus().getValue());
        resp.setAttemptNo(record.getAttemptNo());
        return resp;
    }
}

