  console.log('-------------------------------------------');

  // 3. 用一个较大的起始 userId，避免和真实用户冲突
  const baseUserId = 10000 + Math.floor(Math.random() * 90000);
  const options = ['A', 'B', 'C', 'D'];
  let success = 0;
  let fail = 0;

  for (let i = 0; i < userCount; i++) {
    const userId = baseUserId + i;
    token = generateJwt(userId, false);

