  const count = list.data?.filter(u => u.id === myId).length;
  assert('重复添加后用户仅出现1次', count === 1, count);

  // 清理
  await DEL(`/api/admin/exams/${testExamId}/whitelist`, { userIds: [myId] });

  // 考试重复开始（已有进行中的考试）
  // 先关闭再重新发布（确保 published）
  const examStatus = await GET(`/api/exams/${testExamId}`);
  if (examStatus.data?.status !== 'published') {
    // 可能已经被关闭等，跳过
    console.log('  ⚠️ 试卷不是 published 状态，跳过重复考试测试');
    return;
  }

  const start1 = await POST(`/api/exams/${testExamId}/start`);
  if (start1.code === 200) {
    const start2 = await POST(`/api/exams/${testExamId}/start`);
    assert('有进行中考试时不能再次开始', start2.code !== 200, start2.code);
    assert('错误码=1005(EXAM_IN_PROGRESS)', start2.code === 1005, start2.code);

    // 提交第一次考试以清理
    const answers = (start1.data?.questions || []).map(q => ({
      questionId: q.id,
      answer: 'A',
    }));
    await POST(`/api/exams/${testExamId}/submit`, {
      recordId: start1.data?.recordId,
      answers,
    });
  }
}

// ========== 维度 13: 错误码规范性 ==========
async function testErrorCodeStandard() {
  console.log('\n🔢 13. 错误码规范性');

  // 所有业务错误都不应返回500
  const cases = [
    { name: '不存在试卷', fn: () => GET('/api/exams/999999') },
    { name: '重复发布', fn: () => PUT(`/api/admin/exams/${testExamId}/publish`) },
    { name: '不存在记录', fn: () => GET('/api/records/999999') },
    { name: '无效状态操作', fn: () => PUT(`/api/admin/exams/${testExamId}/reopen`) },
  ];

  for (const c of cases) {
    const res = await c.fn();
    assert(`${c.name} 非500`, res.code !== 500, res.code);
  }

  // 参数校验错误码
  const validationRes = await POST('/api/admin/exams', { title: '' });
  assert('参数校验返回400', validationRes.code === 400, validationRes.code);

  // 未登录错误码
  saveSession();
  token = '';
  const authRes = await GET('/api/auth/me');
  assert('未登录返回401', authRes.code === 401, authRes.code);
  restoreSession();
}

// ========== 清理测试数据 ==========
async function cleanup() {
  console.log('\n🧹 清理测试数据');

  if (testExamId) {
    // 尝试多条路径恢复到可删除状态
    // 先试 unpublish (published → draft)
    await PUT(`/api/admin/exams/${testExamId}/unpublish`);
    let delRes = await DEL(`/api/admin/exams/${testExamId}`);
    if (delRes.code === 200) {
      console.log(`  ✅ 已清理测试试卷 ID=${testExamId}`);
      return;
    }
    // 再试 close (published → closed → delete)
    await PUT(`/api/admin/exams/${testExamId}/close`);
    delRes = await DEL(`/api/admin/exams/${testExamId}`);
    if (delRes.code === 200) {
      console.log(`  ✅ 已清理测试试卷 ID=${testExamId}`);
      return;
    }
    // draft 状态直接删
    delRes = await DEL(`/api/admin/exams/${testExamId}`);
    if (delRes.code === 200) {
      console.log(`  ✅ 已清理测试试卷 ID=${testExamId}`);
    } else {
      console.log(`  ⚠️ 清理试卷失败: ${JSON.stringify(delRes)}`);
    }
  }
}

// ========== JWT 工具 ==========
function generateJwt(userId, isAdmin) {
  const key = Buffer.from(CONFIG.jwtSecret, 'base64');
  const header = Buffer.from(JSON.stringify({ alg: 'HS256', typ: 'JWT' })).toString('base64url');
  const now = Math.floor(Date.now() / 1000);
  const payload = Buffer.from(JSON.stringify({
    userId, isAdmin, iat: now, exp: now + 86400,
  })).toString('base64url');
  const sig = crypto.createHmac('sha256', key)
    .update(`${header}.${payload}`).digest('base64url');
  return `${header}.${payload}.${sig}`;
}

// ========== Mock 考试 ==========
async function mockExam() {
  const userCount = parseInt(process.argv[3]) || CONFIG.mockUserCount;
  const specifiedExamId = process.argv[4] ? parseInt(process.argv[4]) : null;

  console.log(`🎭 Mock 考试 — ${userCount} 人随机答题\n`);

  // 1. 用 admin 登录，找一个可用的试卷
  await login();

  let examId = specifiedExamId;
  let originalStatus = null; // 记录原始状态，mock 完后还原

  if (!examId) {
    const listRes = await GET('/api/admin/exams?page=1&size=100');
    const published = listRes.data?.records?.find(e => e.status === 'published');
    const closed = listRes.data?.records?.find(e => e.status === 'closed' && e.questionCount > 0);
    const target = published || closed;
    if (!target) {
      console.log('❌ 没有找到可用的试卷（published 或 closed 且有题目）');
      process.exit(1);
    }
    examId = target.id;
    originalStatus = target.status;
    console.log(`📋 自动选中试卷: id=${examId}, title=${target.title}, status=${target.status}`);
  } else {
    // 查一下指定试卷的状态
    const listRes = await GET('/api/admin/exams?page=1&size=100');
    const target = listRes.data?.records?.find(e => e.id === examId);
    originalStatus = target?.status || null;
    console.log(`📋 指定试卷: id=${examId}, status=${originalStatus}`);
  }

  // 如果试卷是 closed 状态，先 reopen 变成 published
  if (originalStatus === 'closed') {
    const reopenRes = await PUT(`/api/admin/exams/${examId}/reopen`);
    if (reopenRes.code === 200) {
      console.log(`🔄 试卷已从 closed 重新发布为 published`);
    } else {
      console.log(`❌ reopen 失败: code=${reopenRes.code}, msg=${reopenRes.message || ''}`);
      process.exit(1);
    }
  }

  // 2. 获取题目列表（需要 admin 权限）
  const questionsRes = await GET(`/api/admin/exams/${examId}/questions`);
  if (!questionsRes.data?.length) {
    console.log('❌ 该试卷没有题目');
    process.exit(1);
  }
  console.log(`📝 题目数量: ${questionsRes.data.length}`);
  console.log('-------------------------------------------');

  // 3. 用一个较大的起始 userId，避免和真实用户冲突
  const baseUserId = 10000 + Math.floor(Math.random() * 90000);
  const options = ['A', 'B', 'C', 'D'];
  let success = 0;
  let fail = 0;

  for (let i = 0; i < userCount; i++) {
    const userId = baseUserId + i;
    token = generateJwt(userId, false);

    // 开始考试
    const startRes = await POST(`/api/exams/${examId}/start`);
    if (startRes.code !== 200 || !startRes.data?.recordId) {
      console.log(`❌ 用户 ${userId} 开始考试失败: code=${startRes.code}, msg=${startRes.message || ''}`);
      fail++;
      continue;
    }

    const recordId = startRes.data.recordId;
    const questions = startRes.data.questions || [];

    // 随机答题
    const answers = questions.map(q => ({
      questionId: q.id,
      answer: options[Math.floor(Math.random() * 4)],
    }));

    // 提交考试
    const submitRes = await POST(`/api/exams/${examId}/submit`, { recordId, answers });
    if (submitRes.code === 200) {
      console.log(`✅ 用户 ${userId} 完成考试, 得分: ${submitRes.data?.score}`);
      success++;
    } else {
      console.log(`❌ 用户 ${userId} 提交失败: code=${submitRes.code}, msg=${submitRes.message || ''}`);
      fail++;
    }
  }

  console.log('-------------------------------------------');
  console.log(`🎉 完成! 成功: ${success}, 失败: ${fail}, 总计: ${userCount}`);
  process.exit(fail > 0 ? 1 : 0);
}

// ========== 执行 ==========
async function main() {
  // 支持子命令: node test-api.js mock [人数] [examId]
  if (process.argv[2] === 'mock') {
    return mockExam();
  }

  console.log('🚀 考试系统 - 全量接口测试\n');

  try {
    await login();

    // 维度 1: 正常流程
    await testAdminExamCrud();
    await testQuestionCrud();
    await testExamStatusFlow();
    await testStudentExamFlow();
    await testWhitelist();
    await testAnalysis();

    // 维度 2: 分页边界
    await testPaginationBoundary();

    // 维度 4: 参数校验
    await testParamValidation();

    // 维度 5: 注入防护
    await testInjection();

    // 维度 6: 写操作验证
    await testWriteAndVerify();

    // 维度 7: 权限测试
    await testPermissions();

    // 维度 8: 不存在数据
    await testNotExistData();

    // 维度 9: 并发请求
    await testConcurrency();

    // 维度 10: 响应结构
    await testResponseStructure();

    // 维度 11: 状态约束
    await testStatusConstraints();

    // 维度 12: 数据重复
    await testDuplicateData();

    // 维度 13: 错误码规范
    await testErrorCodeStandard();

    // 清理
    await cleanup();

  } catch (e) {
    if (e.cause?.code === 'ECONNREFUSED') {
      console.log('\n❌ 无法连接后端 http://localhost:18080，请确保后端已启动');
    } else {
      console.log(`\n❌ 异常: ${e.stack || e.message}`);
    }
    process.exit(1);
  }

  console.log(`\n========================================`);
  console.log(`✅ 通过: ${passed}  ❌ 失败: ${failed}  📊 总计: ${passed + failed}`);
  console.log(`========================================`);
  console.log(`\n覆盖维度:`);
  console.log(`  1. 正常流程 (CRUD + 状态流转 + 考试 + 白名单 + 分析)`);
  console.log(`  2. 分页边界`);
  console.log(`  3. 搜索边界 (当前无搜索接口，跳过)`);
  console.log(`  4. 参数校验`);
  console.log(`  5. 注入防护 + 特殊字符`);
  console.log(`  6. 写操作验证`);
  console.log(`  7. 权限测试 (未登录/无效token)`);
  console.log(`  8. 不存在数据`);
  console.log(`  9. 并发请求`);
  console.log(`  10. 响应结构一致性`);
  console.log(`  11. 状态约束 (状态机违规操作)`);
  console.log(`  12. 数据重复检测`);
  console.log(`  13. 错误码规范性`);
  console.log(`\n覆盖接口: 27 个`);
  console.log(`测试账号: dev_user (isAdmin=true, dev profile 自动创建)`);
  process.exit(failed > 0 ? 1 : 0);
}

main();

